mapper.select:
SELECT 
r.h_code,
(
SELECT COUNT(*) FROM reviewboard rb
INNER JOIN room r ON r.r_code = rb.r_code
WHERE rb.rb_score = 1 AND r.h_code = #{h_code}
) AS scoreOne,
(
select COUNT(*) FROM reviewboard rb
INNER JOIN room r ON r.r_code = rb.r_code
WHERE rb.rb_score = 2 AND r.h_code = #{h_code}
) AS scoreTwo,
(
select COUNT(*) FROM reviewboard rb
INNER JOIN room r ON r.r_code = rb.r_code
WHERE rb.rb_score = 3 AND r.h_code = #{h_code}
) AS scoreThr,
(
select COUNT(*) FROM reviewboard rb
INNER JOIN room r ON r.r_code = rb.r_code
WHERE rb.rb_score = 4 AND r.h_code = #{h_code}
) AS scoreFou,
(
select COUNT(*) FROM reviewboard rb
INNER JOIN room r ON r.r_code = rb.r_code
WHERE rb.rb_score = 5 AND r.h_code = #{h_code}
) AS scoreFiv
FROM room r 
WHERE r.h_code = #{h_code}
GROUP BY r.h_code
